   532→func (pp *PostFilterPlugin) PostFilter(ctx context.Context, state *framework.CycleState, pod *v1.Pod, _ framework.NodeToStatusMap) (*framework.PostFilterResult, *framework.Status) {
   533→	pp.numPostFilterCalled++
   534→	nodeInfos, err := pp.fh.SnapshotSharedLister().NodeInfos().List()
   535→	if err != nil {
   536→		return nil, framework.NewStatus(framework.Error, err.Error())
   537→	}
   538→
   539→	for _, nodeInfo := range nodeInfos {
   540→		pp.fh.RunFilterPlugins(ctx, state, pod, nodeInfo)
   541→	}
   542→	pp.fh.RunScorePlugins(ctx, state, pod, nodeInfos)
   543→
   544→	if pp.failPostFilter {
   545→		return nil, framework.NewStatus(framework.Error, fmt.Sprintf("injecting failure for pod %v", pod.Name))
   546→	}
   547→	if pp.rejectPostFilter {
   548→		return nil, framework.NewStatus(framework.Unschedulable, fmt.Sprintf("injecting unschedulable for pod %v", pod.Name))
   549→	}
   550→	if pp.breakPostFilter {
   551→		return nil, framework.NewStatus(framework.UnschedulableAndUnresolvable, fmt.Sprintf("injecting unresolvable for pod %v", pod.Name))
   552→	}
   553→
   554→	return nil, framework.NewStatus(framework.Success, fmt.Sprintf("make room for pod %v to be schedulable", pod.Name))
   555→}
