   562→// Permit implements the permit test plugin.
   563→func (pp *PermitPlugin) Permit(ctx context.Context, state *framework.CycleState, pod *v1.Pod, nodeName string) (*framework.Status, time.Duration) {
   564→	pp.mutex.Lock()
   565→	defer pp.mutex.Unlock()
   566→
   567→	pp.numPermitCalled++
   568→	if pp.failPermit {
   569→		return framework.NewStatus(framework.Error, fmt.Sprintf("injecting failure for pod %v", pod.Name)), 0
   570→	}
   571→	if pp.rejectPermit {
   572→		return framework.NewStatus(framework.Unschedulable, fmt.Sprintf("reject pod %v", pod.Name)), 0
   573→	}
   574→	if pp.timeoutPermit {
   575→		go func() {
   576→			select {
   577→			case <-ctx.Done():
   578→				pp.mutex.Lock()
   579→				defer pp.mutex.Unlock()
   580→				pp.cancelled = true
   581→			}
   582→		}()
   583→		return framework.NewStatus(framework.Wait, ""), 3 * time.Second
   584→	}
   585→	if pp.waitAndRejectPermit || pp.waitAndAllowPermit {
   586→		if pp.waitingPod == "" || pp.waitingPod == pod.Name {
   587→			pp.waitingPod = pod.Name
   588→			return framework.NewStatus(framework.Wait, ""), 30 * time.Second
   589→		}
   590→		if pp.waitAndRejectPermit {
   591→			pp.rejectingPod = pod.Name
   592→			pp.fh.IterateOverWaitingPods(func(wp framework.WaitingPod) {
   593→				wp.Reject(pp.name, fmt.Sprintf("reject pod %v", wp.GetPod().Name))
   594→			})
   595→			return framework.NewStatus(framework.Unschedulable, fmt.Sprintf("reject pod %v", pod.Name)), 0
   596→		}
   597→		if pp.waitAndAllowPermit {
   598→			pp.allowingPod = pod.Name
   599→			pp.allowAllPods()
   600→			return nil, 0
   601→		}
   602→	}
   603→	return nil, 0
   604→}
   605→
   606→// allowAllPods allows all waiting pods.
   607→func (pp *PermitPlugin) allowAllPods() {
   608→	pp.fh.IterateOverWaitingPods(func(wp framework.WaitingPod) { wp.Allow(pp.name) })
   609→}
   610→
   611→// rejectAllPods rejects all waiting pods.
   612→func (pp *PermitPlugin) rejectAllPods() {
   613→	pp.mutex.Lock()
   614→	defer pp.mutex.Unlock()
   615→	pp.fh.IterateOverWaitingPods(func(wp framework.WaitingPod) { wp.Reject(pp.name, "rejectAllPods") })
   616→}
