   619→func TestPreFilterPlugin(t *testing.T) {
   620→	testContext := testutils.InitTestAPIServer(t, "prefilter-plugin", nil)
   621→
   622→	tests := []struct {
   623→		name   string
   624→		fail   bool
   625→		reject bool
   626→	}{
   627→		{
   628→			name:   "disable fail and reject flags",
   629→			fail:   false,
   630→			reject: false,
   631→		},
   632→		{
   633→			name:   "enable fail and disable reject flags",
   634→			fail:   true,
   635→			reject: false,
   636→		},
   637→		{
   638→			name:   "disable fail and enable reject flags",
   639→			fail:   false,
   640→			reject: true,
   641→		},
   642→	}
   643→
   644→	for _, test := range tests {
   645→		t.Run(test.name, func(t *testing.T) {
   646→			// Create a plugin registry for testing. Register only a pre-filter plugin.
   647→			preFilterPlugin := &PreFilterPlugin{}
   648→			registry, prof := initRegistryAndConfig(t, preFilterPlugin)
   649→
   650→			testCtx, teardown := schedulerutils.InitTestSchedulerForFrameworkTest(t, testContext, 2,
   651→				scheduler.WithProfiles(prof),
   652→				scheduler.WithFrameworkOutOfTreeRegistry(registry))
   653→			defer teardown()
   654→
   655→			preFilterPlugin.failPreFilter = test.fail
   656→			preFilterPlugin.rejectPreFilter = test.reject
   657→			// Create a best effort pod.
   658→			pod, err := testutils.CreatePausePod(testCtx.ClientSet,
   659→				testutils.InitPausePod(&testutils.PausePodConfig{Name: "test-pod", Namespace: testCtx.NS.Name}))
   660→			if err != nil {
   661→				t.Errorf("Error while creating a test pod: %v", err)
   662→			}
   663→
   664→			if test.reject {
   665→				if err = testutils.WaitForPodUnschedulable(testCtx.ClientSet, pod); err != nil {
   666→					t.Errorf("Didn't expect the pod to be scheduled. error: %v", err)
   667→				}
   668→			} else if test.fail {
   669→				if err = wait.PollUntilContextTimeout(testCtx.Ctx, 10*time.Millisecond, 30*time.Second, false,
   670→					testutils.PodSchedulingError(testCtx.ClientSet, pod.Namespace, pod.Name)); err != nil {
   671→					t.Errorf("Expected a scheduling error, but got: %v", err)
   672→				}
   673→			} else {
   674→				if err = testutils.WaitForPodToSchedule(testCtx.ClientSet, pod); err != nil {
   675→					t.Errorf("Expected the pod to be scheduled. error: %v", err)
   676→				}
   677→			}
   678→
   679→			if preFilterPlugin.numPreFilterCalled == 0 {
   680→				t.Errorf("Expected the prefilter plugin to be called.")
   681→			}
   682→		})
   683→	}
   684→}
